166	 * with bigint and then it also inherits the valid time range of a bigint.
167	 */
168	static Oid
169	coerce_to_time_type(Oid type)
170	{
171		if (ts_type_is_int8_binary_compatible(type))
172			return INT8OID;
173	
174		elog(ERROR, "unsupported time type \"%s\"", format_type_be(type));
175		pg_unreachable();
176	}
