366	bool
367	policy_refresh_cagg_execute(int32 job_id, Jsonb *config)
368	{
369		PolicyContinuousAggData policy_data;
370	
371		StringInfo str = makeStringInfo();
372		JsonbToCStringIndent(str, &config->root, VARSIZE(config));
373	
374		policy_refresh_cagg_read_and_validate_config(config, &policy_data);
375		bool extend_last_bucket = !policy_refresh_cagg_check_if_last_policy(&policy_data);
376	
377		bool enable_osm_reads_old = ts_guc_enable_osm_reads;
378	
379		if (!policy_data.include_tiered_data_isnull)
380		{
381			SetConfigOption("timescaledb.enable_tiered_reads",
382							policy_data.include_tiered_data ? "on" : "off",
383							PGC_USERSET,
384							PGC_S_SESSION);
385		}
386	
387		ContinuousAggRefreshContext context = { .callctx = CAGG_REFRESH_POLICY };
388	
389		/* Try to split window range into a list of ranges */
390		List *refresh_window_list =
391			continuous_agg_split_refresh_window(policy_data.cagg,
392												&policy_data.refresh_window,
393												policy_data.buckets_per_batch,
394												policy_data.refresh_newest_first);
395		if (refresh_window_list == NIL)
396			refresh_window_list = lappend(refresh_window_list, &policy_data.refresh_window);
397		else
398			context.callctx = CAGG_REFRESH_POLICY_BATCHED;
399	
400		context.number_of_batches = list_length(refresh_window_list);
401	
402		ListCell *lc;
403		int32 processing_batch = 0;
404		foreach (lc, refresh_window_list)
405		{
406			InternalTimeRange *refresh_window = (InternalTimeRange *) lfirst(lc);
407			elog(DEBUG1,
408				 "refreshing continuous aggregate \"%s\" from %s to %s",
409				 NameStr(policy_data.cagg->data.user_view_name),
410				 ts_internal_to_time_string(refresh_window->start, refresh_window->type),
411				 ts_internal_to_time_string(refresh_window->end, refresh_window->type));
412	
413			context.processing_batch = ++processing_batch;
414			continuous_agg_refresh_internal(policy_data.cagg,
415											refresh_window,
416											context,
417											refresh_window->start_isnull,
418											refresh_window->end_isnull,
419											(context.callctx != CAGG_REFRESH_POLICY_BATCHED),
420											false, /* force */
421											policy_data.process_hypertable_invalidations,
422											extend_last_bucket);
423			if (processing_batch >= policy_data.max_batches_per_execution &&
424				processing_batch < context.number_of_batches &&
425				policy_data.max_batches_per_execution > 0)
426			{
427				elog(LOG,
428					 "reached maximum number of batches per execution (%d), batches not processed (%d)",
429					 policy_data.max_batches_per_execution,
430					 context.number_of_batches - processing_batch);
431				break;
432			}
433		}
434	
435		if (!policy_data.include_tiered_data_isnull)
436		{
437			SetConfigOption("timescaledb.enable_tiered_reads",
438							enable_osm_reads_old ? "on" : "off",
439							PGC_USERSET,
440							PGC_S_SESSION);
441		}
442	
443		return true;
444	}
445	
446	void
447	policy_refresh_cagg_read_and_validate_config(Jsonb *config, PolicyContinuousAggData *policy_data)
448	{
449		int32 materialization_id;
450		Hypertable *mat_ht;
451		const Dimension *open_dim;
452		Oid dim_type;
453		int64 refresh_start, refresh_end;
454		int32 buckets_per_batch, max_batches_per_execution;
455		bool start_isnull, end_isnull;
456		bool include_tiered_data, include_tiered_data_isnull;
457		bool refresh_newest_first;
458	
459		materialization_id = policy_continuous_aggregate_get_mat_hypertable_id(config);
460		mat_ht = ts_hypertable_get_by_id(materialization_id);
461	
462		if (!mat_ht)
463			ereport(ERROR,
464					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
465					 errmsg("configuration materialization hypertable id %d not found",
466							materialization_id)));
467	
468		ContinuousAgg *cagg = ts_continuous_agg_find_by_mat_hypertable_id(materialization_id, false);
469	
470		open_dim = get_open_dimension_for_hypertable(mat_ht, true);
471		dim_type = ts_dimension_get_partition_type(open_dim);
472		refresh_start = policy_refresh_cagg_get_refresh_start(cagg, open_dim, config, &start_isnull);
473		refresh_end = policy_refresh_cagg_get_refresh_end(open_dim, config, &end_isnull);
474	
475		if (refresh_start >= refresh_end)
476			ereport(ERROR,
477					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
478					 errmsg("invalid refresh window"),
